import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './App.css';

// 1. LINH HỒN CỦA TRANG ĐĂNG NHẬP
function LoginPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState('');
    const [pass, setPass] = useState('');

    const handleLogin = (e) => {
        e.preventDefault();
        // Tạm thời chấp nhận mọi tài khoản để vào Dashboard
        navigate('/dashboard');
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <h2>HỆ THỐNG NHÂN SỰ</h2>
                <form onSubmit={handleLogin}>
                    <div className="input-group">
                        <label>Username</label>
                        <input type="text" value={user} onChange={(e) => setUser(e.target.value)} required />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input type="password" value={pass} onChange={(e) => setPass(e.target.value)} required />
                    </div>
                    <button type="submit" className="btn-login">ĐĂNG NHẬP</button>
                </form>
            </div>
        </div>
    );
}

// 2. LINH HỒN CỦA TRANG DASHBOARD
function DashboardPage() {
    const [employees, setEmployees] = useState([]);

    useEffect(() => {
        axios.get("http://localhost:8080/api/employees")
            .then(res => setEmployees(res.data))
            .catch(err => console.error("Lỗi kết nối Java:", err));
    }, []);

    return (
        <div className="dashboard-container">
            {/* Sidebar bên trái */}
            <div className="sidebar">
                <div className="sidebar-header">MyAdmin</div>
                <ul className="sidebar-menu">
                    <li>Dashboard</li>
                    <li>Hồ sơ nhân viên</li>
                    <li>Chấm công</li>
                    <li>Hợp đồng</li>
                    <li>Bảng lương</li>
                    <li>Tài khoản</li>
                </ul>
            </div>

            {/* Nội dung bên phải */}
            <div className="main-content">
                <div className="top-bar">
                    <span>HỆ THỐNG QUẢN LÝ NHÂN SỰ</span>
                    <span>Chào Admin | Đăng xuất</span>
                </div>

                <div className="content-body">
                    <div className="stats-grid">
                        <div className="stat-card">
                            <p>Số nhân viên</p>
                            <h4>{employees.length}</h4>
                        </div>
                        <div className="stat-card" style={{borderLeftColor: '#1cc88a'}}>
                            <p>Số giảng viên</p>
                            <h4>12</h4>
                        </div>
                        <div className="stat-card" style={{borderLeftColor: '#f6c23e'}}>
                            <p>Tổng lương tháng</p>
                            <h4>150.000.000 đ</h4>
                        </div>
                    </div>

                    <h3>Danh sách nhân viên chi tiết</h3>
                    <table className="data-table">
                        <thead>
                        <tr>
                            <th>Họ Tên</th>
                            <th>Phòng ban</th>
                            <th>Chức vụ</th>
                        </tr>
                        </thead>
                        <tbody>
                        {employees.map(emp => (
                            <tr key={emp.id}>
                                <td style={{fontWeight: 'bold'}}>{emp.fullName}</td>
                                <td>{emp.department}</td>
                                <td>{emp.position}</td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

// 3. CẤU HÌNH ĐƯỜNG DẪN CHÍNH
function App() {
    return (
        <Router>
            <Routes>
                <Route path="/" element={<LoginPage />} />
                <Route path="/dashboard" element={<DashboardPage />} />
            </Routes>
        </Router>
    );
}

export default App;
